// // This module counts down from 7 to 0 on the rising edge of the clock and resets to 8 when the reset signal is high.
module simple_counter (
    input clk,
    input rst,
    output reg [2:0] count
);

    always @(posedge clk) begin
        if (rst) begin
            count <= 3'd0;
        end else begin
            count <= count + 1;
        end
    end

endmodule
